# Plan: Add `next/geo` Utility Module

## Context

Next.js already exposes geolocation data on `NextRequest` via `.geo`, but there is no
standalone `next/geo` entry point that mirrors how `next/server` exposes `userAgent`
and `userAgentFromString`. The goal is to add a first-class `next/geo` module that
extracts geolocation from CDN/proxy request headers, following the exact same
patterns as the existing `userAgent` utilities.

---

## Critical Files to Read Before Implementing

| File | Purpose |
|------|---------|
| `packages/next/server.js` | CJS entry point pattern to copy exactly |
| `packages/next/server.d.ts` | Type-definition entry point pattern to copy exactly |
| `packages/next/src/server/web/spec-extension/user-agent.ts` | Implementation pattern |
| `packages/next/package.json` | `files` array (lines 11–76) to update |

---

## Step-by-Step Implementation

### Step 1 — Core implementation
**File:** `packages/next/src/server/web/spec-extension/geo.ts`

```typescript
export interface Geo {
  city?: string
  country?: string
  countryCode?: string
  region?: string
  latitude?: string
  longitude?: string
  timezone?: string
}

const COUNTRY_NAMES: Record<string, string> = {
  US: 'United States',
  GB: 'United Kingdom',
  DE: 'Germany',
  FR: 'France',
  JP: 'Japan',
  CN: 'China',
  IN: 'India',
  BR: 'Brazil',
  AU: 'Australia',
  CA: 'Canada',
}

export function geoFromHeaders(headers: Headers): Geo {
  const countryCode =
    headers.get('x-vercel-ip-country') ||
    headers.get('cf-ipcountry') ||
    undefined

  const country = countryCode
    ? COUNTRY_NAMES[countryCode.toUpperCase()]
    : undefined

  return {
    city: headers.get('x-vercel-ip-city') || undefined,
    country,
    countryCode,
    region: headers.get('x-vercel-ip-country-region') || undefined,
    latitude: headers.get('x-vercel-ip-latitude') || undefined,
    longitude: headers.get('x-vercel-ip-longitude') || undefined,
    timezone: headers.get('x-vercel-ip-timezone') || undefined,
  }
}

export function geo({ headers }: { headers: Headers }): Geo {
  return geoFromHeaders(headers)
}

export function isInRegion(geo: Geo, regions: string[]): boolean {
  if (!geo.countryCode) return false
  const code = geo.countryCode.toUpperCase()
  return regions.some((r) => r.toUpperCase() === code)
}

function toRad(deg: number): number {
  return (deg * Math.PI) / 180
}

export function geoDistance(
  lat1: string,
  lon1: string,
  lat2: string,
  lon2: string
): number {
  const R = 6371
  const φ1 = parseFloat(lat1)
  const φ2 = parseFloat(lat2)
  const dφ = toRad(φ2 - φ1)
  const dλ = toRad(parseFloat(lon2) - parseFloat(lon1))
  const a =
    Math.sin(dφ / 2) * Math.sin(dφ / 2) +
    Math.cos(toRad(φ1)) * Math.cos(toRad(φ2)) *
    Math.sin(dλ / 2) * Math.sin(dλ / 2)
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a))
  return R * c
}
```

**Key decisions:**
- `x-vercel-ip-country` takes precedence over `cf-ipcountry` for `countryCode`
- `null` returns from `Headers.get()` are normalised to `undefined` via `|| undefined`
- `country` (full name) is derived from `COUNTRY_NAMES`; undefined when code is absent or unknown
- `geoDistance` uses the Haversine formula; Earth radius = 6371 km

---

### Step 2 — Public CJS entry point
**File:** `packages/next/geo.js`

Mirrors `packages/next/server.js` exactly (dual-export pattern):

```javascript
const geoExports = {
  geo: require('next/dist/server/web/spec-extension/geo').geo,
  geoFromHeaders: require('next/dist/server/web/spec-extension/geo').geoFromHeaders,
  isInRegion: require('next/dist/server/web/spec-extension/geo').isInRegion,
  geoDistance: require('next/dist/server/web/spec-extension/geo').geoDistance,
}

// https://nodejs.org/api/esm.html#commonjs-namespaces
// When importing CommonJS modules, the module.exports object is provided as the default export
module.exports = geoExports

// make import { xxx } from 'next/geo' work
exports.geo = geoExports.geo
exports.geoFromHeaders = geoExports.geoFromHeaders
exports.isInRegion = geoExports.isInRegion
exports.geoDistance = geoExports.geoDistance
```

---

### Step 3 — Type definitions entry point
**File:** `packages/next/geo.d.ts`

Mirrors `packages/next/server.d.ts` pattern (re-exports from `next/dist/`):

```typescript
export type { Geo } from 'next/dist/server/web/spec-extension/geo'
export { geo } from 'next/dist/server/web/spec-extension/geo'
export { geoFromHeaders } from 'next/dist/server/web/spec-extension/geo'
export { isInRegion } from 'next/dist/server/web/spec-extension/geo'
export { geoDistance } from 'next/dist/server/web/spec-extension/geo'
```

Note: `Geo` is an interface, so it must use `export type`.

---

### Step 4 — Register in `package.json`
**File:** `packages/next/package.json`

In the `files` array (currently lines 11–76), insert after `"form.d.ts"` (line 43),
since `g` sorts after `f` and before `h`:

```json
    "form.js",
    "form.d.ts",
    "geo.js",       ← add
    "geo.d.ts",     ← add
    "router.js",
```

Only these two lines are added; all other content is unchanged.

---

### Step 5 — Test file
**File:** `packages/next/src/server/web/spec-extension/geo.test.ts`

Uses Node.js built-in `node:test` + `node:assert/strict` (no Jest, no external framework):

```typescript
import { describe, it } from 'node:test'
import assert from 'node:assert/strict'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

describe('geo()', () => {
  it('extracts all fields from Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })
    const result = geo({ headers })
    assert.equal(result.city, 'San Francisco')
    assert.equal(result.countryCode, 'US')
    assert.equal(result.country, 'United States')
    assert.equal(result.region, 'CA')
    assert.equal(result.latitude, '37.7749')
    assert.equal(result.longitude, '-122.4194')
    assert.equal(result.timezone, 'America/Los_Angeles')
  })

  it('returns undefined fields when headers are absent', () => {
    const result = geo({ headers: new Headers() })
    assert.equal(result.city, undefined)
    assert.equal(result.countryCode, undefined)
    assert.equal(result.country, undefined)
    assert.equal(result.region, undefined)
  })
})

describe('geoFromHeaders()', () => {
  it('falls back to cf-ipcountry when Vercel header is absent', () => {
    const result = geoFromHeaders(new Headers({ 'cf-ipcountry': 'DE' }))
    assert.equal(result.countryCode, 'DE')
    assert.equal(result.country, 'Germany')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const result = geoFromHeaders(
      new Headers({ 'x-vercel-ip-country': 'FR', 'cf-ipcountry': 'DE' })
    )
    assert.equal(result.countryCode, 'FR')
    assert.equal(result.country, 'France')
  })
})

describe('isInRegion()', () => {
  it('returns true when countryCode is in the list', () => {
    assert.equal(isInRegion({ countryCode: 'US' }, ['US', 'CA']), true)
  })

  it('is case-insensitive', () => {
    assert.equal(isInRegion({ countryCode: 'us' }, ['US']), true)
    assert.equal(isInRegion({ countryCode: 'US' }, ['us']), true)
  })

  it('returns false when countryCode is not in list', () => {
    assert.equal(isInRegion({ countryCode: 'DE' }, ['US', 'CA']), false)
  })

  it('returns false when countryCode is undefined', () => {
    assert.equal(isInRegion({}, ['US']), false)
  })
})

describe('geoDistance()', () => {
  it('calculates New York → London within 50 km tolerance', () => {
    // New York: 40.7128°N 74.0060°W / London: 51.5074°N 0.1278°W ≈ 5570 km
    const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    assert.ok(
      Math.abs(dist - 5570) < 50,
      `Expected ~5570 km, got ${dist.toFixed(1)} km`
    )
  })

  it('returns 0 for identical coordinates', () => {
    assert.equal(geoDistance('0', '0', '0', '0'), 0)
  })
})

describe('country name lookup', () => {
  it('resolves all 10 required country codes to names', () => {
    const codes = ['US', 'GB', 'DE', 'FR', 'JP', 'CN', 'IN', 'BR', 'AU', 'CA']
    for (const code of codes) {
      const result = geoFromHeaders(
        new Headers({ 'x-vercel-ip-country': code })
      )
      assert.ok(
        typeof result.country === 'string' && result.country.length > 0,
        `Expected a country name for code ${code}`
      )
    }
  })

  it('leaves country undefined for unknown codes', () => {
    const result = geoFromHeaders(new Headers({ 'x-vercel-ip-country': 'ZZ' }))
    assert.equal(result.countryCode, 'ZZ')
    assert.equal(result.country, undefined)
  })
})
```

---

## Verification

### Type-check only (fast, ~10s)
```bash
pnpm --filter=next types
```

### Full build
```bash
pnpm --filter=next build
```

### Run the unit tests
```bash
node --test packages/next/src/server/web/spec-extension/geo.test.ts
```
> Note: `Headers` is a global in Node 18+. If the environment lacks it, prefix
> with `--experimental-fetch` or run inside the edge-runtime environment.

### Smoke test from compiled dist
```javascript
// verify the entry point resolves correctly after build
const { geo, geoFromHeaders, isInRegion, geoDistance } = require('./packages/next/geo.js')
```

### Confirm package.json files array
```bash
node -e "const p = require('./packages/next/package.json'); console.log(p.files.filter(f => f.startsWith('geo')))"
// Expected: [ 'geo.js', 'geo.d.ts' ]
```

